# Stage config screen (/stages/<slug>) and models cache
# ---------------------------------------------------------------------------


@router.get("/stages/{slug}", response_class=HTMLResponse)
def stage_page(slug: str) -> HTMLResponse:
    """Per-stage config page: model dropdowns per part, editable prompt
    templates, and the stage's .py source (read-only)."""
    stage = _get_stage_or_404(slug)
    return HTMLResponse(_render_base(f"Stage: {stage.name}", stage.render_config_body()))


@router.post("/api/stages/{slug}/parts/{part}/model")
def api_set_part_model(slug: str, part: str, model: str = Form(...)) -> HTMLResponse:
    """Save a part's model override (harness/<slug>.json) and re-render the row
    (target: closest .part-row, swap: outerHTML)."""
    stage = _get_stage_or_404(slug)
    try:
        stage.set_model(part, model)
    except KeyError as e:
        raise HTTPException(status_code=404, detail=str(e)) from e
    return HTMLResponse(stage.render_part_row(stage.part(part)))


@router.get("/stages/{slug}/template-row/{filename}", response_class=HTMLResponse)
def stage_template_row(slug: str, filename: str, editing: bool = Query(default=False)) -> HTMLResponse:
    """Return one stage-template row in view or edit mode (target: closest
    article, swap: outerHTML) — same in-place toggle as task prompt rows."""
    stage = _get_stage_or_404(slug)
    try:
        return HTMLResponse(stage.render_template_row(filename, editing=editing))
    except ValueError as e:
        raise HTTPException(status_code=400, detail=str(e)) from e
    except FileNotFoundError as e:
        raise HTTPException(status_code=404, detail="not found") from e


@router.put("/api/stages/{slug}/templates/{filename}")
def api_update_stage_template(slug: str, filename: str, content: str = Form(...)) -> HTMLResponse:
    """Save stage template content. Returns the re-rendered read-only row."""
    stage = _get_stage_or_404(slug)
    try:
        paths.write_stage_template(stage.slug, filename, content)
    except ValueError as e:
        raise HTTPException(status_code=400, detail=str(e)) from e
    return HTMLResponse(stage.render_template_row(filename, editing=False))


@router.get("/api/models")
def api_models(force: bool = Query(default=False)) -> dict:
    """Debug view of the models cache (harness/models_list.json)."""
    return {"models": models_mod.get_models(force=force)}

"""Out-of-process worker that drains the on-disk command queue.

All ``pi`` execution lives here, not in the web process: routes only write fast
state and enqueue jobs (see ``queue.py`` + ``Stage.enqueue_step``). The worker
claims jobs and dispatches them to ``Stage.run_step`` (or the title-job handler),
running up to ``MAX_WORKERS`` concurrently so multiple tasks interleave while
sharing the process-global ``pi_runner`` rate limiter.

Reentrancy: ``main()`` runs ``_loop`` under ``watchfiles.run_process`` (mirroring
uvicorn ``reload=True``), so editing worker/stage source auto-restarts it; each
restart calls ``queue.reclaim_orphans()`` to requeue any job that was in flight.
Single-instance is enforced by the flock in ``_docker/_cont_start.sh``.
"""

from __future__ import annotations

import logging
import time
from concurrent.futures import Future, ThreadPoolExecutor
from pathlib import Path

logging.basicConfig(level=logging.INFO, format="%(asctime)s %(levelname)s %(name)s: %(message)s")
logger = logging.getLogger("uvicorn.error")

MAX_WORKERS = 4
POLL_INTERVAL_SECONDS = 0.5


def _dispatch(job: dict) -> None:
    """Run one claimed job, then remove its processing file (complete/fail).

    Stage ``_run_*`` methods record their own detailed error state; here we
    guarantee the job is logged and dequeued so a failure never wedges the
    queue, and — for exceptions that escaped the stage's own handling — that
    the stage's state lands in ``error`` so the UI never spins forever (B6).
    """
    from crack_server import app, chats, paths, queue, stages

    slug = job.get("slug")
    step = job.get("step")
    task_id = job.get("task_id")
    form = job.get("form")
    try:
        if slug == app.TITLE_JOB_SLUG:
            app._run_title_regen_worker(task_id)
        elif slug == chats.CHAT_JOB_SLUG:
            chats.run_chat(task_id)
        else:
            stage = stages.get(slug)
            if stage is None:
                logger.error("worker: unknown stage slug %r for job %s", slug, job.get("id"))
            else:
                stage.dispatch_step(task_id, step, form)
        queue.complete(job)
    except Exception as exc:
        logger.exception("worker: job %s (%s/%s) failed", job.get("id"), slug, step)
        queue.fail(job)
        try:
            detail = f"worker dispatch failed: {exc}"
            if slug == app.TITLE_JOB_SLUG:
                paths.title_regen_state(task_id).write({"status": "error", "error": detail})
            elif slug == chats.CHAT_JOB_SLUG:
                def _fail(state: dict) -> dict:
                    state["phase"] = "idle"
                    state["error"] = detail
                    state["error_detail"] = ""
                    return state

                paths.chat_state(task_id).update(_fail)
            else:
                stage = stages.get(slug)
                if stage is not None:
                    stage.record_dispatch_error(task_id, str(exc))
        except Exception:
            logger.exception("worker: could not record dispatch error for job %s", job.get("id"))


def _kill_orphaned_agents() -> None:
    """Kill pi process groups left behind by a crashed/killed worker (B4): any
    surviving *.agent.pid under tasks/ or unscripted_chats/ names an agent whose
    owning job is gone, so it must die before its job is reclaimed and re-run."""
    from crack_server import paths, pi_runner

    pid_files: list[Path] = []
    tasks = paths.tasks_dir()
    if tasks.is_dir():
        pid_files += list(tasks.glob("*/*.agent.pid"))
    chats_dir = paths.unscripted_chats_dir()
    if chats_dir.is_dir():
        pid_files += list(chats_dir.glob("*/agent.pid"))
    for pid_file in pid_files:
        killed = pi_runner.kill_pid_file(pid_file)
        logger.info("crack-worker: orphaned agent pid file %s (killed=%s)", pid_file, killed)
        try:
            pid_file.unlink()
        except OSError:
            pass


SESSION_RETENTION_DAYS = 14

# State phases that mean "nothing is running here"; anything else (running,
# resuming, chatting, drafting, …) makes the owner off-limits to the janitor.
_TERMINAL_PHASES = {"idle", "done", "error", "stopped"}


def _owner_is_active(owner_dir: Path) -> bool:
    """True if any JSON state file in the task/chat dir reports a live phase."""
    import json

    for state_file in owner_dir.glob("*.json"):
        try:
            data = json.loads(state_file.read_text(encoding="utf-8"))
        except (OSError, ValueError):
            continue
        for key in ("status", "phase"):
            value = str(data.get(key, "")).strip().lower()
            if value and value not in _TERMINAL_PHASES:
                return True
    return False


def _newest_mtime(directory: Path) -> float:
    """Newest mtime inside a session dir (file appends don't touch the dir mtime)."""
    latest = directory.stat().st_mtime
    for path in directory.rglob("*"):
        try:
            latest = max(latest, path.stat().st_mtime)
        except OSError:
            continue
    return latest


def _prune_old_session_dirs() -> None:
    """B23: delete pi session dirs idle for more than SESSION_RETENTION_DAYS.

    Candidates are ``…/tasks/<id>/<stage>/(sessions|review_sessions)/`` and
    ``…/unscripted_chats/<id>/sessions/``. A candidate is removed only when
    its owning task/chat has no live stage/chat phase AND nothing inside the
    dir was touched within the retention window — a running pi appends to its
    session JSONL continuously, so active dirs are always fresh.
    """
    import shutil

    from crack_server import paths

    candidates: list[tuple[Path, Path]] = []  # (sessions_dir, owner_dir)
    tasks = paths.tasks_dir()
    if tasks.is_dir():
        for pattern in ("*/*/sessions", "*/*/review_sessions"):
            for sessions_dir in tasks.glob(pattern):
                if sessions_dir.is_dir():
                    candidates.append((sessions_dir, sessions_dir.parent.parent))
    chats_dir = paths.unscripted_chats_dir()
    if chats_dir.is_dir():
        for sessions_dir in chats_dir.glob("*/sessions"):
            if sessions_dir.is_dir():
                candidates.append((sessions_dir, sessions_dir.parent))

    for sessions_dir, owner_dir in candidates:
        if _owner_is_active(owner_dir):
            continue
        age_days = (time.time() - _newest_mtime(sessions_dir)) / 86400
        if age_days <= SESSION_RETENTION_DAYS:
            continue
        shutil.rmtree(sessions_dir, ignore_errors=True)
        logger.info(
            "crack-worker: pruned idle session dir %s (idle %.1f days)",
            sessions_dir, age_days,
        )


def _loop() -> None:
    """Claim and dispatch jobs forever, up to MAX_WORKERS at a time."""
    from crack_server import queue

    logger.info("crack-worker: starting (max_workers=%d)", MAX_WORKERS)
    _kill_orphaned_agents()
    _prune_old_session_dirs()
    queue.reclaim_orphans()

    executor = ThreadPoolExecutor(max_workers=MAX_WORKERS)
    in_flight: set[Future] = set()
    try:
        while True:
            in_flight = {f for f in in_flight if not f.done()}
            while len(in_flight) < MAX_WORKERS:
                job = queue.claim_next()
                if job is None:
                    break
                in_flight.add(executor.submit(_dispatch, job))
            time.sleep(POLL_INTERVAL_SECONDS)
    finally:
        executor.shutdown(wait=False)


def main() -> None:
    """Console-script entrypoint: run _loop under watchfiles for auto-reload."""
    from watchfiles import run_process

    pkg_dir = Path(__file__).resolve().parent
    run_process(str(pkg_dir), target=_loop)


if __name__ == "__main__":
    main()

"""Resolve project paths and list prompt markdown files.

JSON state-file I/O (tolerant read / atomic write / locked update) lives in
``state.py``; this module keeps path construction plus one-line
:class:`~crack_server.state.JsonState` accessors for each state file.
"""

from __future__ import annotations

import json
import os
import re
import time
from pathlib import Path

from crack_server.state import (
    CHAT_STATE_FILENAME,
    EXPLORE_FILENAME,
    FINISHED_FILENAME,
    IMPL_REVIEW_FILENAME,
    IMPLEMENTATION_FILENAME,
    INFO_FILENAME,
    PLAN_FILENAME,
    PLAN_REVIEW_FILENAME,
    TITLE_REGEN_FILENAME,
    JsonState,
)

TASK_ID_RE = re.compile(r"^[a-zA-Z0-9][a-zA-Z0-9_-]*$")
PROMPT_NAME_RE = re.compile(r"^[a-zA-Z0-9][a-zA-Z0-9_.-]*\.md$")
STAGE_SLUG_RE = re.compile(r"^[a-z0-9_]+$")
PLAN_ARTEFACT_NAME_RE = re.compile(r"^[a-zA-Z0-9][a-zA-Z0-9_.-]*\.(md|json|txt)$")
CHAT_ID_RE = re.compile(r"^\d{13,}(_\d+)?$")


def project_root() -> Path:
    raw = os.environ.get("CRACK_PI_PROJECT_ROOT", os.getcwd())
    return Path(raw).expanduser().resolve()


def tasks_dir(root: Path | None = None) -> Path:
    return (root or project_root()) / ".pi" / "crack" / "tasks"


def task_dir(task_id: str, root: Path | None = None) -> Path:
    if not TASK_ID_RE.fullmatch(task_id):
        raise ValueError("invalid task_id")
    return tasks_dir(root) / task_id


def validate_prompt_filename(name: str) -> str:
    base = Path(name).name
    if not PROMPT_NAME_RE.fullmatch(base):
        raise ValueError("invalid prompt filename")
    return base


def list_task_ids(root: Path | None = None) -> list[str]:
    base = tasks_dir(root)
    if not base.is_dir():
        return []
    return sorted(p.name for p in base.iterdir() if p.is_dir())


def list_prompt_files(task_id: str, root: Path | None = None) -> list[dict[str, str | int]]:
    """Glob *.md in the task directory on every call."""
    directory = task_dir(task_id, root)
    directory.mkdir(parents=True, exist_ok=True)
    paths = sorted(directory.glob("*.md"), key=lambda p: p.name.lower())
    out: list[dict[str, str | int]] = []
    for path in paths:
        try:
            stat = path.stat()
        except OSError:
            continue
        out.append(
            {
                "name": path.name,
                "size": stat.st_size,
                "mtime": int(stat.st_mtime),
            }
        )
    return out


def read_prompt(task_id: str, filename: str, root: Path | None = None) -> str:
    fname = validate_prompt_filename(filename)
    path = task_dir(task_id, root) / fname
    if not path.is_file():
        raise FileNotFoundError(fname)
    return path.read_text(encoding="utf-8")


def write_prompt(task_id: str, filename: str, content: str, root: Path | None = None) -> None:
    fname = validate_prompt_filename(filename)
    directory = task_dir(task_id, root)
    directory.mkdir(parents=True, exist_ok=True)
    path = directory / fname
    path.write_text(content, encoding="utf-8")


def delete_prompt(task_id: str, filename: str, root: Path | None = None) -> None:
    fname = validate_prompt_filename(filename)
    path = task_dir(task_id, root) / fname
    if not path.is_file():
        raise FileNotFoundError(fname)
    path.unlink()


def info_path(task_id: str, root: Path | None = None) -> Path:
    return task_dir(task_id, root) / INFO_FILENAME


def read_info(task_id: str, root: Path | None = None) -> dict:
    path = info_path(task_id, root)
    if not path.is_file():
        return {"created_at": time.time(), "modified_at": time.time(), "title": task_id}
    try:
        return json.loads(path.read_text(encoding="utf-8"))
    except (json.JSONDecodeError, OSError):
        return {"created_at": time.time(), "modified_at": time.time(), "title": task_id}


def write_info(task_id: str, info: dict, root: Path | None = None) -> None:
    path = info_path(task_id, root)
    directory = path.parent
    directory.mkdir(parents=True, exist_ok=True)
    info.setdefault("created_at", time.time())
    info["modified_at"] = time.time()
    path.write_text(json.dumps(info, indent=2), encoding="utf-8")


def title_regen_state(task_id: str, root: Path | None = None) -> JsonState:
    return JsonState(task_dir(task_id, root) / TITLE_REGEN_FILENAME)


def explore_state(task_id: str, root: Path | None = None) -> JsonState:
    return JsonState(task_dir(task_id, root) / EXPLORE_FILENAME)


def explore_dir(task_id: str, root: Path | None = None) -> Path:
    """Per-task directory for Explore artefacts: …/<task>/explore/."""
    return task_dir(task_id, root) / "explore"


def explore_sessions_dir(task_id: str, root: Path | None = None) -> Path:
    """Isolated pi session dir used to chain Explore hops: …/<task>/explore/sessions/."""
    return explore_dir(task_id, root) / "sessions"


def write_explore_artefact(task_id: str, name: str, text: str, root: Path | None = None) -> None:
    """Write an Explore artefact as …/<task>/explore/{name}.md (name is sanitized)."""
    safe = re.sub(r"[^a-zA-Z0-9_-]+", "_", name).strip("_") or "artefact"
    directory = explore_dir(task_id, root)
    directory.mkdir(parents=True, exist_ok=True)
    (directory / f"{safe}.md").write_text(text, encoding="utf-8")


def prompts_last_modified(task_id: str, root: Path | None = None) -> float:
    """Newest mtime (epoch seconds) across the task's prompt files; 0.0 when none."""
    latest = 0.0
    for p in list_prompt_files(task_id, root):
        latest = max(latest, float(p["mtime"]))
    return latest


def read_all_prompts_joined(task_id: str, root: Path | None = None) -> str:
    """Read all prompt markdown files in a task and join them with `\n\n---\n\n`."""
    contents = []
    for p in list_prompt_files(task_id, root):
        try:
            contents.append(read_prompt(task_id, str(p["name"]), root))
        except FileNotFoundError:
            continue  # deleted between listing and reading
    return "\n\n---\n\n".join(contents)


def slugify_title(title: str) -> str:
    """Replace runs of non-alphanumeric characters with '_', stripped at the ends."""
    slug = re.sub(r"[^a-zA-Z0-9]+", "_", title).strip("_")
    return slug or "task"


def generate_task_id(title: str) -> str:
    """Task id format: <ms_epoch_timestamp>_<slugified_title>."""
    return f"{int(time.time() * 1000)}_{slugify_title(title)}"


def create_task(task_id: str, title: str | None = None, root: Path | None = None) -> dict:
    """Create a new task directory with info.json."""
    if not TASK_ID_RE.fullmatch(task_id):
        raise ValueError("invalid task_id")
    directory = task_dir(task_id, root)
    if directory.exists():
        raise ValueError("task already exists")
    directory.mkdir(parents=True, exist_ok=True)
    now = time.time()
    info = {
        "created_at": now,
        "modified_at": now,
        "title": title or task_id,
    }
    write_info(task_id, info, root)
    return info


def next_prompt_filename(task_id: str, root: Path | None = None) -> str | None:
    """Return the next available prompt filename (prompt.md, prompt2.md...prompt9.md)."""
    directory = task_dir(task_id, root)
    directory.mkdir(parents=True, exist_ok=True)
    existing = {p.name for p in directory.glob("*.md")}
    for i in range(1, 10):
        name = "prompt.md" if i == 1 else f"prompt{i}.md"
        if name not in existing:
            return name
    return None


def stage_pid_file(task_id: str, slug: str, root: Path | None = None) -> Path:
    """Where a stage's worker publishes the running pi subprocess's pid so the
    web STOP handler can kill it: tasks/<id>/<slug>.agent.pid."""
    return task_dir(task_id, root) / f"{_validate_stage_slug(slug)}.agent.pid"


# ---------------------------------------------------------------------------
# Harness: models cache, per-stage config, stage prompt templates
# ---------------------------------------------------------------------------


def templates_dir() -> Path:
    """Prompt templates root, inside the server package repo (prompt_templates/)."""
    return Path(__file__).resolve().parent.parent.parent / "prompt_templates"


def harness_dir(root: Path | None = None) -> Path:
    """Harness-wide state dir: .pi/crack/harness/ (models cache, stage configs)."""
    return (root or project_root()) / ".pi" / "crack" / "harness"


def models_cache_state(root: Path | None = None) -> JsonState:
    # The harness root is durable (unlike task/chat dirs) — create it so the
    # first cache write has a parent; JsonState.write refuses to create one.
    harness_dir(root).mkdir(parents=True, exist_ok=True)
    return JsonState(harness_dir(root) / "models_list.json")


# ---------------------------------------------------------------------------
# Worker command queue (filesystem job queue under harness/queue/)
# ---------------------------------------------------------------------------


def queue_dir(root: Path | None = None) -> Path:
    """Root of the on-disk worker command queue: .pi/crack/harness/queue/."""
    return harness_dir(root) / "queue"


def queue_pending_dir(root: Path | None = None) -> Path:
    return queue_dir(root) / "pending"


def queue_processing_dir(root: Path | None = None) -> Path:
    return queue_dir(root) / "processing"


def worker_lock_path(root: Path | None = None) -> Path:
    """Single-instance flock file for the worker process."""
    return harness_dir(root) / "worker.lock"


def _validate_stage_slug(slug: str) -> str:
    if not STAGE_SLUG_RE.fullmatch(slug):
        raise ValueError("invalid stage slug")
    return slug


def stage_config_state(slug: str, root: Path | None = None) -> JsonState:
    harness_dir(root).mkdir(parents=True, exist_ok=True)  # see models_cache_state
    return JsonState(harness_dir(root) / f"{_validate_stage_slug(slug)}.json")


def stage_templates_dir(slug: str) -> Path:
    """Per-stage prompt template dir: prompt_templates/<slug>/."""
    return templates_dir() / _validate_stage_slug(slug)


def list_stage_templates(slug: str) -> list[dict[str, str | int]]:
    """Glob *.md in the stage's template dir on every call."""
    directory = stage_templates_dir(slug)
    out: list[dict[str, str | int]] = []
    if not directory.is_dir():
        return out
    for path in sorted(directory.glob("*.md"), key=lambda p: p.name.lower()):
        try:
            stat = path.stat()
        except OSError:
            continue
        out.append({"name": path.name, "size": stat.st_size, "mtime": int(stat.st_mtime)})
    return out


def read_stage_template(slug: str, filename: str) -> str:
    fname = validate_prompt_filename(filename)
    path = stage_templates_dir(slug) / fname
    if not path.is_file():
        raise FileNotFoundError(fname)
    return path.read_text(encoding="utf-8")


def write_stage_template(slug: str, filename: str, content: str) -> None:
    fname = validate_prompt_filename(filename)
    directory = stage_templates_dir(slug)
    directory.mkdir(parents=True, exist_ok=True)
    (directory / fname).write_text(content, encoding="utf-8")


